// Client for the "Ask this site" Worker (see worker/). Streams a grounded answer
// token-by-token. The endpoint is read from a build-time constant or a
// localStorage override, so it can be set after deploying without a rebuild.

const DEFAULT_ENDPOINT = 'https://ask-henry.whenry6688.workers.dev';

function endpoint() {
  try {
    return (localStorage.getItem('askEndpoint') || DEFAULT_ENDPOINT).trim();
  } catch {
    return DEFAULT_ENDPOINT;
  }
}

export function askConfigured() {
  return !!endpoint();
}

// Async generator yielding answer text chunks as they stream in. Parses the
// Workers AI SSE format: lines of `data: {"response":"..."}`, ending at `[DONE]`.
export async function* askStream(question, contexts) {
  const url = endpoint();
  if (!url) throw new Error('ask endpoint not configured');

  const res = await fetch(url, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ question, contexts }),
  });
  if (!res.ok || !res.body) throw new Error(`ask failed: ${res.status}`);

  const reader = res.body.getReader();
  const decoder = new TextDecoder();
  let buffer = '';

  for (;;) {
    const { value, done } = await reader.read();
    if (done) break;
    buffer += decoder.decode(value, { stream: true });

    const events = buffer.split('\n\n');
    buffer = events.pop() || ''; // keep the trailing partial event
    for (const evt of events) {
      const line = evt.split('\n').find((l) => l.startsWith('data:'));
      if (!line) continue;
      const data = line.slice(5).trim();
      if (data === '[DONE]') return;
      try {
        const json = JSON.parse(data);
        if (json.response) yield json.response;
      } catch {
        // ignore keep-alives / non-JSON lines
      }
    }
  }
}
